blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie nauczysz się budować <strong>zdania przeczące i pytające</strong> w stronie biernej, a także udzielać <strong>krótkich odpowiedzi</strong> na pytania tak/nie.",
    "rules": [
        {
            "label": "Odmowa",
            "color": "rose",
            "text": "Dodaj <strong>nie</strong> po be:",
            "example": "The house isn't made of wood."
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "text": "<strong>być</strong> jest na pierwszym miejscu:",
            "example": "Was it built in 1990?"
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "emerald",
            "text": "<strong>Tak/Nie + temat + być</strong>:",
            "example": "Yes, it was. / No, it wasn't."
        }
    ]
}

{
    "title": "1. Sprzeciw w czasie teraźniejszym prostym biernym",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Wzór: <strong>jest/jest/jest + nie + V3</strong>. Formy skrócone: <strong>nie jest, nie jest</strong>",
            "examples": [
                {
                    "en": "The products are not made in China.",
                    "ua": "Produkty nie są produkowane w Chinach."
                },
                {
                    "en": "This material isn't used anymore.",
                    "ua": "Ten materiał nie jest już używany."
                },
                {
                    "en": "I am not invited to the party.",
                    "ua": "Nie zostałem zaproszony na imprezę."
                },
                {
                    "en": "The doors aren't locked at night.",
                    "ua": "Drzwi nie są zamykane na noc."
                }
            ]
        },
        {
            "label": "Niuanse",
            "color": "amber",
            "description": "Formularz <strong>nie jestem</strong> nie jest skracany do „nie jestem”. Używamy: <strong>Nie jestem</strong>",
            "examples": [
                {
                    "en": "I'm not included in the list.",
                    "ua": "Nie jestem uwzględniony na liście."
                }
            ]
        }
    ]
}

{
    "title": "2. Odmowa w czasie Past Simple Passive",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Wzór: <strong>był/był + nie + V3</strong>. W skrócie: <strong>nie było, nie było</strong>",
            "examples": [
                {
                    "en": "The house was not built in 1990.",
                    "ua": "Dom nie został wybudowany w 1990r."
                },
                {
                    "en": "The letter wasn't sent yesterday.",
                    "ua": "List wczoraj nie został wysłany."
                },
                {
                    "en": "We were not informed about the changes.",
                    "ua": "Nie zostaliśmy powiadomieni o zmianach."
                },
                {
                    "en": "The tickets weren't sold out.",
                    "ua": "Bilety nie zostały wyprzedane."
                }
            ]
        }
    ]
}

{
    "title": "3. Odmowa w innych czasach",
    "sections": [
        {
            "label": "Przyszłość prosta",
            "color": "rose",
            "description": "<strong>nie będzie (nie będzie) + będzie + V3</strong>",
            "examples": [
                {
                    "en": "The project will not be finished on time.",
                    "ua": "Projekt nie zostanie ukończony w terminie."
                },
                {
                    "en": "The meeting won't be held tomorrow.",
                    "ua": "Jutro spotkanie nie odbędzie się."
                }
            ]
        },
        {
            "label": "Czas teraźniejszy idealny",
            "color": "rose",
            "description": "<strong>był/był + nie + był + V3</strong>. Скорочені: <strong>nie, nie</strong>",
            "examples": [
                {
                    "en": "The work has not been completed yet.",
                    "ua": "Praca nie jest jeszcze ukończona."
                },
                {
                    "en": "The files haven't been uploaded.",
                    "ua": "Pliki nie zostały przesłane."
                }
            ]
        }
    ]
}

{
    "title": "4. Pytania Tak/Nie w stronie biernej",
    "sections": [
        {
            "label": "Czas teraźniejszy prosty",
            "color": "blue",
            "description": "<strong>Jestem/jest/jestem + S + V3?</strong>",
            "examples": [
                {
                    "en": "Is English spoken here?",
                    "ua": "Czy mówią tu po angielsku?"
                },
                {
                    "en": "Are the rooms cleaned daily?",
                    "ua": "Czy pokoje są sprzątane codziennie?"
                },
                {
                    "en": "Am I included in the team?",
                    "ua": "Czy jestem częścią zespołu?"
                }
            ]
        },
        {
            "label": "Czas przeszły prosty",
            "color": "blue",
            "description": "<strong>Był/był + S + V3?</strong>",
            "examples": [
                {
                    "en": "Was the house built in 1990?",
                    "ua": "Czy dom został zbudowany w 1990 roku?"
                },
                {
                    "en": "Were the documents signed?",
                    "ua": "Czy dokumenty zostały podpisane?"
                }
            ]
        },
        {
            "label": "Przyszłość prosta",
            "color": "blue",
            "description": "<strong>Czy + S + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "Will the project be finished on time?",
                    "ua": "Czy projekt zostanie ukończony w terminie?"
                },
                {
                    "en": "Will you be invited to the meeting?",
                    "ua": "Czy zostaniesz zaproszony na spotkanie?"
                }
            ]
        },
        {
            "label": "Czas teraźniejszy idealny",
            "color": "blue",
            "description": "<strong>Czy + S + było + V3?</strong>",
            "examples": [
                {
                    "en": "Has the work been completed?",
                    "ua": "Czy praca jest ukończona?"
                },
                {
                    "en": "Have the tickets been sold?",
                    "ua": "Czy bilety są sprzedane?"
                }
            ]
        }
    ]
}

{
    "title": "5. Krótkie odpowiedzi (Krótkie odpowiedzi)",
    "sections": [
        {
            "label": "Reguła",
            "color": "emerald",
            "description": "Struktura: <strong>Tak/Nie + zaimek podmiotu + być (w tym samym czasie)</strong>",
            "examples": [
                {
                    "en": "Is the door locked? — Yes, it is. / No, it isn't.",
                    "ua": "Czy drzwi są zamknięte? - Tak. / NIE."
                },
                {
                    "en": "Was the letter sent? — Yes, it was. / No, it wasn't.",
                    "ua": "Czy list został wysłany? - Tak. / NIE."
                },
                {
                    "en": "Are they invited? — Yes, they are. / No, they aren't.",
                    "ua": "Czy zostali zaproszeni? - Tak. / NIE."
                }
            ]
        },
        {
            "label": "Czas teraźniejszy idealny",
            "color": "emerald",
            "description": "У Czas teraźniejszy idealny: <strong>Tak/Nie + S + ma/ma</strong>",
            "examples": [
                {
                    "en": "Has the work been finished? — Yes, it has. / No, it hasn't.",
                    "ua": "Czy praca jest skończona? - Tak. / NIE."
                },
                {
                    "en": "Have they been informed? — Yes, they have. / No, they haven't.",
                    "ua": "Czy zostali powiadomieni? - Tak. / NIE."
                }
            ]
        },
        {
            "label": "Przyszłość prosta",
            "color": "emerald",
            "description": "У Przyszłość: <strong>Tak/Nie + S + będzie/nie będzie</strong>",
            "examples": [
                {
                    "en": "Will it be done tomorrow? — Yes, it will. / No, it won't.",
                    "ua": "Czy uda się to zrobić jutro? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Pytanie „Wh” w stronie biernej",
    "sections": [
        {
            "label": "Struktura",
            "color": "sky",
            "description": "<strong>Jakie-słowo + być + S + V3?</strong>",
            "examples": [
                {
                    "en": "Where is coffee grown?",
                    "ua": "Gdzie uprawia się kawę?"
                },
                {
                    "en": "When was the house built?",
                    "ua": "Kiedy dom został zbudowany?"
                },
                {
                    "en": "How are these products made?",
                    "ua": "Jak powstają te produkty?"
                },
                {
                    "en": "Why was the meeting cancelled?",
                    "ua": "Dlaczego spotkanie zostało odwołane?"
                }
            ]
        },
        {
            "label": "Kto/Co jako temat",
            "color": "sky",
            "description": "Gdy podmiotem jest słowo pytające: <strong>Kto/Co + być + V3?</strong> (bez inwersji)",
            "examples": [
                {
                    "en": "What is produced here?",
                    "ua": "Co się tutaj produkuje?"
                },
                {
                    "en": "Who was invited to the party?",
                    "ua": "Kto został zaproszony na imprezę?"
                }
            ]
        }
    ]
}

{
    "title": "7. Tabela zbiorcza pytań i zastrzeżeń",
    "intro": "Główne struktury zastrzeżeń i pytań w różnych momentach:",
    "rows": [
        {
            "en": "Present Simple",
            "ua": "Nie jest tu robione.",
            "note": "Is it made here? — Yes, it is. / No, it isn't."
        },
        {
            "en": "Past Simple",
            "ua": "Nie został zbudowany w 1990 r.",
            "note": "Was it built in 1990? — Yes, it was. / No, it wasn't."
        },
        {
            "en": "Future Simple",
            "ua": "To nie będzie skończone.",
            "note": "Will it be finished? — Yes, it will. / No, it won't."
        },
        {
            "en": "Present Perfect",
            "ua": "Nie zostało to zrobione.",
            "note": "Has it been done? — Yes, it has. / No, it hasn't."
        }
    ]
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Kolejność słów w pytaniu jest nieprawidłowa.",
            "wrong": "The house was built in 1990?",
            "right": "✅ Was the house built in 1990?"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pominięcie czasownika pomocniczego w pytaniu.",
            "wrong": "It made in China?",
            "right": "✅ Is it made in China?"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niekompletna krótka odpowiedź.",
            "wrong": "Was it built? — Yes, it.",
            "right": "✅ Yes, it was."
        }
    ]
}

{
    "title": "9. Krótkie podsumowanie",
    "items": [
        "Zastrzeżenie: <strong>być + nie + V3</strong> (nie jest, nie było, nie będzie, nie było).",
        "Pytanie typu „tak/nie”: <strong>być</strong> pojawia się na pierwszym miejscu przed podmiotem.",
        "Krótkie odpowiedzi: <strong>Tak/Nie + temat + być</strong> (w tym samym czasie).",
        "Pytanie: <strong>Jakie słowo + być + S + V3?</strong>",
        "Kiedy Kto/Co jest podmiotem, nie jest potrzebne odwracanie: <strong>Co jest produkowane?</strong>"
    ]
}
